import{_ as e,o as r,c as n,a2 as t}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"MSC 地中海航運（Mediterranean Shipping Company）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/航運產業/03_全球航商競爭格局/03-1_MSC_地中海航運.md","filePath":"Deep32Q知識庫/產業洞察/航運產業/03_全球航商競爭格局/03-1_MSC_地中海航運.md"}'),o={name:"Deep32Q知識庫/產業洞察/航運產業/03_全球航商競爭格局/03-1_MSC_地中海航運.md"};function i(l,a,s,p,_,g){return r(),n("div",null,[...a[0]||(a[0]=[t('<h1 id="msc-地中海航運-mediterranean-shipping-company" tabindex="-1">MSC 地中海航運（Mediterranean Shipping Company） <a class="header-anchor" href="#msc-地中海航運-mediterranean-shipping-company" aria-label="Permalink to &quot;MSC 地中海航運（Mediterranean Shipping Company）&quot;">​</a></h1><h2 id="基本資訊" tabindex="-1">基本資訊 <a class="header-anchor" href="#基本資訊" aria-label="Permalink to &quot;基本資訊&quot;">​</a></h2><ul><li><strong>全球排名</strong>：第1名（最大貨櫃航運公司）</li><li><strong>總部</strong>：瑞士日內瓦（Geneva, Switzerland）</li><li><strong>成立</strong>：1970年，由Gianluigi Aponte創立</li><li><strong>2026年2月數據</strong>：船隊運力突破720萬TEU，運營980艘船舶，全球市場佔有率21.4%</li></ul><h2 id="擴張策略與訂單" tabindex="-1">擴張策略與訂單 <a class="header-anchor" href="#擴張策略與訂單" aria-label="Permalink to &quot;擴張策略與訂單&quot;">​</a></h2><p>MSC在2025-2026年間持續積極擴張，是全球貨櫃運能增長最激進的航商：</p><ul><li><strong>訂單簿</strong>：截至2026年2月，訂單簿約218萬TEU（前十大航商中排名第四，但絕對量最大）</li><li><strong>超大型船訂單</strong>：2025年7月將6艘19,000 TEU船舶放大至22,000 TEU，並加訂4艘同型船（預計2028年下半年交船）；2026年1月再訂6艘11,400 TEU雙燃料LNG船舶（2029年交船，附4艘選擇權）</li><li><strong>小型船更新</strong>：2025年7月啟動「大型計畫」更新feeder船隊，預計訂造120艘1,100-5,000 TEU船舶，交船延伸至2029年</li><li><strong>二手船收購</strong>：截至2026年3月的一年內購買65艘船舶（約23萬TEU）；自2020年以來累計購買超過400艘，總計約160萬TEU</li><li><strong>冷藏運力</strong>：2025年4月至2026年間，冷藏插頭容量增加近10萬個（增長15.3%），為全球最大增幅</li></ul><h2 id="競爭優勢" tabindex="-1">競爭優勢 <a class="header-anchor" href="#競爭優勢" aria-label="Permalink to &quot;競爭優勢&quot;">​</a></h2><p>MSC的核心競爭力在於：</p><ol><li><strong>獨立運營模式</strong>：脫離2M聯盟後選擇獨立運營，提供直接港口對港口的廣泛服務網絡</li><li><strong>靈活的船隊策略</strong>：同時經營超大型船、中型船和feeder船，覆蓋所有航線</li><li><strong>垂直整合</strong>：在主要港口投資碼頭和物流設施，控制供應鏈關鍵節點</li><li><strong>家族企業文化</strong>：由Aponte家族掌控，決策快速靈活</li></ol><h2 id="_2026年展望" tabindex="-1">2026年展望 <a class="header-anchor" href="#_2026年展望" aria-label="Permalink to &quot;2026年展望&quot;">​</a></h2><p>MSC預計2026年全球貨櫃市場將面臨高度複雜性和不確定性，受地緣政治緊張和全球貿易模式演變影響。公司持續擴大船隊規模，維持其全球最大貨櫃航運公司的地位。</p><hr><p><strong>資料來源</strong>：Global Trade Magazine (2026-02)、gCaptain (2026-02)、TNS Logistics (2026)、Port Technology (2026)、Forbes (2025-11)</p>',13)])])}const c=e(o,[["render",i]]);export{h as __pageData,c as default};
